-- WHO/OMS growth reference data for nutrition charts.
-- Source: WHO Growth reference data for 5-19 years, expanded z-score tables.
-- Note: weight-for-age is only published by WHO for 5-10 years.

create table if not exists public.who_growth_reference (
  id uuid primary key default gen_random_uuid(),
  indicator text not null,
  sex text not null,
  age_months integer not null,
  l numeric not null,
  m numeric not null,
  s numeric not null,
  source text not null default 'WHO Growth reference data for 5-19 years',
  created_at timestamptz not null default now(),
  unique (indicator, sex, age_months),
  check (indicator in ('bmi_for_age', 'weight_for_age', 'height_for_age')),
  check (sex in ('M', 'F')),
  check (age_months > 0)
);

create index if not exists idx_who_growth_reference_lookup
  on public.who_growth_reference(indicator, sex, age_months);

alter table public.who_growth_reference enable row level security;

drop policy if exists authenticated_read_who_growth_reference on public.who_growth_reference;
create policy authenticated_read_who_growth_reference on public.who_growth_reference
  for select to authenticated
  using (true);

grant select on public.who_growth_reference to authenticated;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

on conflict (indicator, sex, age_months) do update set
  l = excluded.l,
  m = excluded.m,
  s = excluded.s,
  source = excluded.source;

comment on table public.who_growth_reference is
  'Static WHO/OMS LMS reference values for nutrition growth charts. Weight-for-age is available for 5-10 years only.';
